import React from 'react';
import { motion } from 'framer-motion';
import Navbar from '../components/layout/Navbar';
import Footer from '../components/layout/Footer';
import Hero from '../components/sections/Hero';
import Value from '../components/sections/Value';
import Container from '../components/layout/Container';
import Section from '../components/layout/Section';
import Card from '../components/ui/Card';

const Home = () => {
  return (
    <div className="min-h-screen bg-primary">
      <Navbar />
      <Hero />
      {/* Services Section */}
      <Section className="bg-secondary">
        <Container>
          <motion.div
            initial={{ opacity: 0, y: 40 }}
            whileInView={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6 }}
            viewport={{ once: true }}
            className="text-center mb-20"
          >
            <h2 className="text-4xl md:text-5xl font-bold tracking-tight text-text-primary mb-6">
              Solutions I Provide
            </h2>
            <p className="text-lg text-text-secondary max-w-2xl mx-auto">
              I deliver high-quality, scalable, and efficient solutions tailored to your business needs.
            </p>
          </motion.div>

          <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-8">
            {[
              {
                title: 'Web Development',
                description: 'Custom websites and web applications built with the latest technologies for optimal performance, security, and scalability.',
                icon: 'fas fa-code'
              },
              {
                title: 'UI/UX Design',
                description: 'Beautiful, intuitive interfaces designed with user experience at the forefront.',
                icon: 'fas fa-paint-brush'
              },
              {
                title: 'Mobile Development',
                description: 'Cross-platform mobile applications that deliver native-like performance.',
                icon: 'fas fa-mobile-alt'
              },
              {
                title: 'API Development',
                description: 'Robust and well-documented RESTful APIs that power your applications.',
                icon: 'fas fa-plug'
              },
              {
                title: 'E-commerce Solutions',
                description: 'Custom e-commerce solutions that drive sales and enhance customer experience.',
                icon: 'fas fa-shopping-cart'
              },
              {
                title: 'Ongoing Support',
                description: 'Reliable maintenance and support services to keep your digital products running smoothly.',
                icon: 'fas fa-headset'
              }
            ].map((service, index) => (
              <motion.div
                key={index}
                initial={{ opacity: 0, y: 40 }}
                whileInView={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.6, delay: index * 0.1 }}
                viewport={{ once: true }}
              >
                <Card className="h-full">
                  <div className="w-16 h-16 bg-accent rounded-2xl flex items-center justify-center mb-6">
                    <i className={`${service.icon} text-white text-2xl`}></i>
                  </div>
                  <h3 className="text-2xl font-bold text-text-primary mb-4">
                    {service.title}
                  </h3>
                  <p className="text-text-secondary leading-relaxed mb-6">
                    {service.description}
                  </p>
                  <motion.a
                    href="#contact"
                    className="inline-flex items-center text-accent hover:text-accent/80 font-medium transition-colors"
                    whileHover={{ x: 5 }}
                  >
                    Get Started <i className="fas fa-arrow-right ml-2"></i>
                  </motion.a>
                </Card>
              </motion.div>
            ))}
          </div>
        </Container>
      </Section>

      {/* Portfolio Section */}
      <Section>
        <Container>
          <motion.div
            initial={{ opacity: 0, y: 40 }}
            whileInView={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6 }}
            viewport={{ once: true }}
            className="text-center mb-20"
          >
            <h2 className="text-4xl md:text-5xl font-bold tracking-tight text-text-primary mb-6">
              Strategic Digital Solutions
            </h2>
            <p className="text-lg text-text-secondary max-w-2xl mx-auto">
              Delivering measurable results through innovative digital solutions that drive business growth.
            </p>
          </motion.div>

          <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-8">
            {[
              {
                title: 'Web Application System',
                description: 'A comprehensive web application with modern UI/UX, responsive design, and robust backend functionality.',
                image: './images/View Project/web application system.png',
                tags: ['Web Development', 'Full Stack']
              },
              {
                title: 'Data Analytics and Power BI',
                description: 'Interactive dashboards and data visualization solutions for business intelligence and analytics.',
                image: './images/View Project/Data Analytics and power bi.png',
                tags: ['Data Analytics', 'Power BI']
              },
              {
                title: 'Intelligent Fraud Detection',
                description: 'AI-powered fraud detection system that identifies and prevents fraudulent activities in real-time.',
                image: './images/View Project/intelligent fraud system.png',
                tags: ['AI/ML', 'Security']
              }
            ].map((project, index) => (
              <motion.div
                key={index}
                initial={{ opacity: 0, y: 40 }}
                whileInView={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.6, delay: index * 0.1 }}
                viewport={{ once: true }}
                whileHover={{ y: -5 }}
                className="group"
              >
                <Card className="overflow-hidden p-0">
                  <div className="relative h-64 overflow-hidden">
                    <img 
                      src={project.image} 
                      alt={project.title}
                      className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-110" 
                    />
                    <div className="absolute inset-0 bg-gradient-to-t from-black/70 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300 flex items-end p-6">
                      <div className="flex gap-2">
                        {project.tags.map((tag, tagIndex) => (
                          <span key={tagIndex} className="px-3 py-1 text-xs font-medium text-white bg-accent rounded-full">
                            {tag}
                          </span>
                        ))}
                      </div>
                    </div>
                  </div>
                  <div className="p-6">
                    <h3 className="text-xl font-bold text-text-primary mb-2">{project.title}</h3>
                    <p className="text-text-secondary mb-4">{project.description}</p>
                    <div className="flex gap-3">
                      <motion.a
                        href="#"
                        className="px-4 py-2 text-sm font-medium text-text-secondary bg-surface rounded-lg hover:bg-surface-elevated transition-colors"
                        whileHover={{ scale: 1.05 }}
                        whileTap={{ scale: 0.95 }}
                      >
                        View Project
                      </motion.a>
                      <motion.a
                        href="#"
                        className="px-4 py-2 text-sm font-medium text-white bg-accent rounded-lg hover:bg-accent/80 transition-colors"
                        whileHover={{ scale: 1.05 }}
                        whileTap={{ scale: 0.95 }}
                      >
                        Live Demo
                      </motion.a>
                    </div>
                  </div>
                </Card>
              </motion.div>
            ))}
          </div>
